#include <bits/stdc++.h>
using namespace std;
int mo(int x,int y){
	if(x>=0)
		return x%y;
	else
		return (y-(-x)%y)%y;
}
int n,m,a[102],s[102],dp[2][102][102][10];
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		a[i+n]=a[i];
	}
	memset(dp[0],127,sizeof(dp[0]));
	for(int i=1;i<2*n;i++)
		dp[0][i][i][1]=dp[1][i][i][1]=mo(a[i],10),s[i]=s[i-1]+a[i];
	for(int l=2;l<=n;l++)
		for(int i=1;i+l-1<2*n;i++){
			int j=i+l-1;
			for(int k=1;k<=min(m,l);k++){
				if(k==1)
					dp[0][i][j][k]=dp[1][i][j][k]=mo(s[j]-s[i-1],10);
				else
					for(int t=i+k-2;t<j;t++){
						dp[0][i][j][k]=min(dp[0][i][j][k],dp[0][i][t][k-1]*mo(s[j]-s[t],10));
						dp[1][i][j][k]=max(dp[1][i][j][k],dp[1][i][t][k-1]*mo(s[j]-s[t],10));
					}
			}
		}
	int ans1=2e9,ans2=0;
	for(int i=1;i+n-1<2*n;i++)
		ans1=min(ans1,dp[0][i][i+n-1][m]),ans2=max(ans2,dp[1][i][i+n-1][m]);
	printf("%d\n%d",ans1,ans2);
	return 0;
}
